import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";

export function SobaDetalji() {
  const { idSoba } = useParams();
  const [rezervacije, setRezervacije] = useState([]);
  const [emailGost, setEmailGost] = useState("");
  const [datumOd, setDatumOd] = useState("");
  const [datumDo, setDatumDo] = useState("");
  const [brojOsoba, setBrojOsoba] = useState("");

  // Učitavanje rezervacija za tu sobu
  useEffect(() => {
    fetch(`http://localhost:8080/reservations/getReservationsForRoom/${idSoba}`)
      .then((res) => res.json())
      .then((data) => {
        if (data && data.data && data.data.values) {
          setRezervacije(data.data.values);
        }
      })
      .catch((err) =>
        console.error("Greška pri učitavanju rezervacija za sobu:", err)
      );
  }, [idSoba]);

  // Dodavanje nove rezervacije
  const handleAddReservation = async (e) => {
    e.preventDefault();

    const novaRez = {
      email: emailGost,
      brojSobe: parseInt(idSoba),
      datumOd,
      datumDo,
      brojOsoba: parseInt(brojOsoba),
    };

    try {
      const response = await fetch(
        "http://localhost:8080/reservations/createByReceptionist",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(novaRez),
        }
      );
      const data = await response.json();
      alert(data.message || "Rezervacija je uspešno dodata!");

      // Osvježi prikaz rezervacija
      setRezervacije((prev) => [...prev, novaRez]);
    } catch (err) {
      console.error("Greška:", err);
      alert("Greška pri kreiranju rezervacije!");
    }
  };

  return (
    <>
      <NavBarRecepcionar />
      <div style={{ padding: "40px" }}>
        <h2>Rezervacije za sobu #{idSoba}</h2>

        {rezervacije.length > 0 ? (
          <table
            style={{
              width: "100%",
              borderCollapse: "collapse",
              marginTop: "20px",
            }}
          >
            <thead>
              <tr style={{ backgroundColor: "#e7b7ffff" }}>
                <th>ID</th>
                <th>Gost</th>
                <th>Datum prijave</th>
                <th>Datum odjave</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {rezervacije.map((r) => (
                <tr key={r.idRezervacija}>
                  <td>{r.idRezervacija}</td>
                  <td>{r.gost?.email || "Nepoznat"}</td>
                  <td>{r.datumPrijave}</td>
                  <td>{r.datumOdjave}</td>
                  <td>{r.statusRezervacije}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p>Nema rezervacija za ovu sobu.</p>
        )}

        <hr style={{ margin: "30px 0" }} />

        <h3>Kreiraj novu rezervaciju</h3>
        <form onSubmit={handleAddReservation}>
          <label>Email gosta:</label>
          <input
            type="email"
            value={emailGost}
            onChange={(e) => setEmailGost(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px", width: "300px" }}
          />

          <label>Datum prijave:</label>
          <input
            type="date"
            value={datumOd}
            onChange={(e) => setDatumOd(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px" }}
          />

          <label>Datum odjave:</label>
          <input
            type="date"
            value={datumDo}
            onChange={(e) => setDatumDo(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px" }}
          />

          <label>Broj osoba:</label>
          <input
            type="number"
            value={brojOsoba}
            onChange={(e) => setBrojOsoba(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px", width: "100px" }}
          />

          <button
            type="submit"
            style={{
              backgroundColor: "#b84aff",
              color: "white",
              border: "none",
              padding: "8px 15px",
              borderRadius: "6px",
              cursor: "pointer",
            }}
          >
            Dodaj rezervaciju
          </button>
        </form>
      </div>
      <Footer />
    </>
  );
}
